import React, { useState, useEffect } from "react";
import {
  Card,
  CardActionArea,
  CardContent,
  CardMedia,
  Typography,
  Box,
  CircularProgress,
} from "@mui/material";
import { fetchImage } from "../services/api";

const sanitizeText = (text) => {
  const element = document.createElement("div");
  element.innerText = text;
  return element.innerHTML;
};

function ReflectionCard({ reflection }) {
  const [imageLoaded, setImageLoaded] = useState(false);
  const [imageError, setImageError] = useState(false);
  const [imageUrl, setImageUrl] = useState(null);

  useEffect(() => {
    const loadImage = async () => {
      try {
        const blob = await fetchImage(reflection.id, "reflection");
        const blobUrl = URL.createObjectURL(blob);
        setImageUrl(blobUrl);
        setImageLoaded(true);
      } catch (error) {
        setImageError(true);
        console.error("Fetch error:", error);
      }
    };
    loadImage();
  }, [reflection.id]);

  const preventImageDownload = (e) => {
    e.preventDefault();
  };

  return (
    <Card
      elevation={3}
      sx={{
        display: "flex",
        flexDirection: "column",
        m: 2,
        borderRadius: 2,
        height: "100%",
      }}
    >
      <CardActionArea sx={{ flex: 1 }}>
        <Box
          sx={{
            height: {
              xs: 200,
              sm: 250,
              md: 250,
              lg: 300,
              xl: 300,
            },
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            position: "relative",
            borderTopLeftRadius: 2,
            borderTopRightRadius: 2,
            overflow: "hidden",
            p: 2,
          }}
          onContextMenu={preventImageDownload}
        >
          {imageUrl && (
            <CardMedia
              component="img"
              alt={sanitizeText(reflection.title)}
              image={imageUrl}
              title={sanitizeText(reflection.title)}
              sx={{
                height: "110%",
                objectFit: "contain",
                pointerEvents: "none",
              }}
              onDragStart={(e) => e.preventDefault()}
            />
          )}
          {!imageLoaded && !imageError && (
            <CircularProgress
              size={24}
              sx={{
                position: "absolute",
                top: "50%",
                left: "50%",
                transform: "translate(-50%, -50%)",
              }}
            />
          )}
          {imageError && (
            <Typography
              variant="body2"
              color="error"
              sx={{
                position: "absolute",
                top: "50%",
                left: "50%",
                transform: "translate(-50%, -50%)",
              }}
            >
              Image failed to load
            </Typography>
          )}
          <Box
            sx={{
              position: "absolute",
              top: 0,
              left: 0,
              width: "100%",
              height: "100%",
              zIndex: 1,
              backgroundColor: "rgba(0, 0, 0, 0.001)",
            }}
          />
        </Box>
        <CardContent
          sx={{
            display: "flex",
            flexDirection: "column",
            justifyContent: "space-between",
            flexGrow: 1,
            p: 2,
          }}
        >
          <Typography gutterBottom variant="h6">
            {sanitizeText(reflection.title)}
          </Typography>
          <Typography variant="body2" color="textSecondary">
            {sanitizeText(reflection.description)}
          </Typography>
        </CardContent>
      </CardActionArea>
    </Card>
  );
}

export default ReflectionCard;
